Bash(bun -e '
const envFile = await Bun.file\("".env""\).text\(\);
const NOTION_TOKEN = envFile.match\(/NOTION_TOKEN=\(.+\)/\)?.[1]?.trim\(\);

const DATAVAULT_ID = ""2ee58fe7-31b1-81c4-90f7-dc7b3cfba202"";

const reports = [
  { id: ""2dc58fe7-31b1-8099-87f7-ddd385cfd7a4"", name: ""Zeffy"" },
  { id: ""2dc58fe7-31b1-80d9-a295-e65be675e4af"", name: ""Wonderment"" },
  { id: ""2dc58fe7-31b1-8041-9842-e5fa8ce0345a"", name: ""Wavyy"" },
  { id: ""2dc58fe7-31b1-8098-881f-c5d4f2d56431"", name: ""Waverly"" },
  { id: ""2dc58fe7-31b1-8007-9fd4-c3e53ad09c62"", name: ""Vasco"" },
  { id: ""2dc58fe7-31b1-8007-a777-f30dd797bc10"", name: ""Three Ships"" },
  { id: ""2dc58fe7-31b1-80ac-bc22-f26b7441212a"", name: ""Shakepay"" },
  { id: ""2dc58fe7-31b1-80cf-8f28-d9bb0c627c2b"", name: ""Screenloop"" },
  { id: ""2dc58fe7-31b1-80bd-afbd-f0f3f2326d95"", name: ""Ripple AI"" },
  { id: ""2dc58fe7-31b1-8052-99a7-f9686b2fb179"", name: ""Pivohub"" },
  { id: ""2dc58fe7-31b1-8028-873e-cf51db6b6fbd"", name: ""Nolk"" },
  { id: ""2dc58fe7-31b1-80cb-8378-d39aca674037"", name: ""Kotn"" },
];

console.log\(""Creating first batch \(12 reports\)...\\n""\);

for \(const report of reports\) {
  const pageUrl = `https://www.notion.so/${report.id.replace\(/-/g, """"\)}`;

  const body = {
    parent: { database_id: DATAVAULT_ID },
    properties: {
      ""Name"": {
        title: [{ text: { content: `${report.name} - 2025 Investment Report` } }]
      },
      ""Description"": {
        rich_text: [{ text: { content: `Annual investment report and analysis for ${report.name} \(2025\). Compiled from email communications and Claude research.` } }]
      },
      ""URL"": {
        url: pageUrl
      },
      ""Type"": {
        select: { name: ""Analysis"" }
      },
      ""Source"": {
        select: { name: ""Other"" }
      },
      ""Status"": {
        select: { name: ""To Review"" }
      },
      ""Date Added"": {
        date: { start: ""2026-01-21"" }
      },
      ""Tags"": {
        multi_select: [
          { name: ""Investment"" },
          { name: ""Stoic"" },
          { name: ""2025"" }
        ]
      }
    }
  };

  const response = await fetch\(""https://api.notion.com/v1/pages"", {
    method: ""POST"",
    headers: {
      ""Authorization"": `Bearer ${NOTION_TOKEN}`,
      ""Notion-Version"": ""2022-06-28"",
      ""Content-Type"": ""application/json"",
    },
    body: JSON.stringify\(body\)
  }\);

  if \(response.ok\) {
    console.log\(`✅ ${report.name}`\);
  } else {
    const err = await response.json\(\);
    console.log\(`❌ ${report.name}: ${err.message}`\);
  }
}
')
